module RefModule (
    input clk,
    input reset_n,
    input en,
    input load,
    input [7:0] load_val,
    output reg [7:0] q);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset_n or posedge dbg_halt) begin
    if (!reset_n)
        q <= 8'b00000000;
    else if (load)
        q <= load_val;
    else if (en)
        q <= q + 1;
end

endmodule
